mapper.select:
SELECT /* CanCustMapper.selectRclCustList */ RCL.CONTRACT_NUM AS CONTRACT_NUM , SUB.SVC_CNTR_NO AS SVC_CNTR_NO , FN_GET_CODENM('MSP0003', SUB.SUB_STATUS) AS SUB_STATUS_NM , TO_CHAR(TO_DATE(RCL.RCL_DTTM,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS RCL_DTTM , FN_GET_CODENM('MSP0004', RCL.RCL_CODE) AS RCL_RSN , TO_CHAR(TO_DATE(SUBSTR(RCL.CAN_INFO, 0, 14),'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS RCL_CAN_DTTM , FN_GET_CODENM('MSP0012', SUBSTR(RCL.CAN_INFO, 15)) AS RCL_CAN_RSN , DECODE(SUB.SUB_STATUS, 'C', SUBSTR(SUB.SUB_STATUS_DATE,0,8)) AS CAN_DTTM , CASE WHEN SUB.SUB_STATUS = 'C' THEN FN_GET_CODENM('MSP0012', SUB.SUB_STATUS_RSN_CODE) ELSE NULL END AS CAN_RSN , ( SELECT B.DATA_TYPE FROM MSP_JUO_FEATURE_INFO A , MSP_RATE_MST B WHERE A.CONTRACT_NUM = SUB.CONTRACT_NUM AND A.SERVICE_TYPE = 'P' AND A.EVNT_TRTM_DT = ( SELECT MAX(EVNT_TRTM_DT) FROM MSP_JUO_FEATURE_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM AND SERVICE_TYPE = 'P' ) AND A.SOC = B.RATE_CD AND ROWNUM = 1 ) AS DATA_TYPE , NVL(TRIM(SUBSTR(DTL.FST_MODEL_INFO, 21 , 30)), DTL.REQ_USIM_NAME) AS FST_MODEL , DTL.REQ_BUY_TYPE_NM AS REQ_BUY_TYPE_NM , DTL.FST_RATE_CD AS FST_RATE_CD , DTL.FST_RATE_NM AS FST_RATE_NM , FN_GET_ORGNM(SUB.OPEN_AGNT_CD) AS OPEN_AGNT_NM , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD' ), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE , DTL.OPER_TYPE_NM AS OPER_TYPE_NM , PI.BF_COMM_CMPN_NM AS BF_COMM_CMPN_NM , ( SELECT NVL((SELECT NVL(DTL_CD_NM,NP_COMM_CMPN_ID) FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'NSC' AND DTL_CD = NP_COMM_CMPN_ID), (SELECT NVL(DTL_CD_NM,NP_COMM_CMPN_ID) FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'NSC' AND EXPNSN_STR_VAL1 = NP_COMM_CMPN_ID AND USE_YN = 'Y')) FROM MDS_PORTOUT_MST MPM WHERE MPM.CONTRACT_NUM = SUB.CONTRACT_NUM ) AS NP_COMM_CMPN_NM , DTL.SHOP_NM AS SHOP_NM , FN_GET_CODENM('RCP0007', DTL.ON_OFF_TYPE) AS ON_OFF_TYPE_NM , DTL.OPEN_MARKET_REFERER AS OPEN_MARKET_REFERER , CASE WHEN DTL.CSTMR_TYPE = 'JP' OR DTL.CSTMR_TYPE = 'PP' THEN 0 ELSE FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) END AS AGE , CASE WHEN DTL.CSTMR_TYPE = 'JP' OR DTL.CSTMR_TYPE = 'PP' THEN '' ELSE SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) END AS GENDER , SUB.MODEL_NAME AS MODEL_NAME , DTL.LST_RATE_CD AS LST_RATE_CD , DTL.LST_RATE_NM AS LST_RATE_NM , CASE WHEN MSD.REQ_USIM_SN IS NOT NULL THEN '직영온라인' ELSE FN_GET_ORGNM(PUM.ORGN_ID) END AS USIM_ORG_NM , FN_GET_ORGNM(PUM.ORGN_ID) AS FST_USIM_ORG_NM , DECODE(SUB.USIM_TYPE, 'E' , 'Y' , 'N') AS ESIM_YN , DTL.FST_ESIM_YN AS FST_ESIM_YN FROM ( SELECT RCL.CONTRACT_NUM , RCL.STRT_DTTM RCL_DTTM , RCL.SUB_STATUS_RSN_CODE RCL_CODE , MAX(CAN.STRT_DTTM||CAN.SUB_STATUS_RSN_CODE) CAN_INFO FROM ( SELECT CONTRACT_NUM , EVNT_CHANGE_DATE AS STRT_DTTM , SUB_STATUS_RSN_CODE FROM MSP_JUO_SUB_INFO_HIST WHERE EVNT_CD = 'RCL' ) RCL , ( SELECT CONTRACT_NUM , EVNT_CHANGE_DATE AS STRT_DTTM , SUB_STATUS_RSN_CODE FROM MSP_JUO_SUB_INFO_HIST WHERE EVNT_CD = 'CAN' ) CAN WHERE RCL.CONTRACT_NUM = CAN.CONTRACT_NUM AND RCL.STRT_DTTM > CAN.STRT_DTTM GROUP BY RCL.CONTRACT_NUM, RCL.STRT_DTTM, RCL.SUB_STATUS_RSN_CODE ) RCL , MSP_JUO_SUB_INFO SUB , MSP_REQUEST_DTL DTL , MDS_PORTIN_MST PI , NMCP_USIM_BUY_TXN@DL_MCP MSD , MSP_PARTNER_USIM_MST PUM WHERE RCL.CONTRACT_NUM = SUB.CONTRACT_NUM AND SUB.CONTRACT_NUM = DTL.CONTRACT_NUM AND SUB.CONTRACT_NUM = PI.CONTRACT_NUM(+) AND SUB.ICC_ID = MSD.REQ_USIM_SN(+) AND DTL.FST_USIM_NO = PUM.USIM_NO(+) AND SUB.PPPO = 'PO'
AND RCL.RCL_DTTM BETWEEN #{searchStartDt}||'000000' AND #{searchEndDt}||'235959'
AND SUB.CONTRACT_NUM = #{searchName}
AND SUB.OPEN_AGNT_CD = #{cntpntShopId}
ORDER BY RCL.RCL_DTTM DESC
